Settings_Vtiger_Detail_Js("Settings_Mail_Detail_Js",{},{registerAcceptanceEvent:function(){jQuery(".contentsDiv").on("click",".acceptanceRecord",function(e){var t=this,n=jQuery.progressIndicator();AppConnector.request({module:app.getModuleName(),parent:app.getParentModuleName(),action:"SaveAjax",mode:"acceptanceRecord",id:$("#recordId").val()}).then(function(e){n.progressIndicator({mode:"hide"}),Settings_Vtiger_Index_Js.showMessage({text:e.result.message}),$(t).remove()},function(e){n.progressIndicator({mode:"hide"})})})},sendMailManually:function(){var e=jQuery(".contentsDiv");e.on("click",".sendManually",function(t){var n=jQuery.progressIndicator();AppConnector.request({module:app.getModuleName(),parent:app.getParentModuleName(),action:"SendManuallyAjax",id:e.find("#recordId").val()}).then(function(t){n.progressIndicator({mode:"hide"}),Settings_Vtiger_Index_Js.showMessage({text:t.result.message}),e.find(".sendManually").remove(),e.find(".deleteButton").remove()},function(e){n.progressIndicator({mode:"hide"})})})},registerEvents:function(){this.registerAcceptanceEvent(),this.sendMailManually()}});